<?php
namespace App\Console\Commands;
use App\Domain\Wallet\GoldReasonCode; use App\Domain\Wallet\WalletService; use App\Models\Character; use Illuminate\Console\Command;
class CreditCharacterWalletCommand extends Command {protected $signature='game:wallet:credit {characterId} {amount} {--reason=admin_grant} {--description=}';protected $description='Credit character gold (local/testing only)';public function handle(WalletService $s){if(app()->environment('production')){$this->error('Unavailable in production.');return 1;}$c=Character::find($this->argument('characterId'));$a=filter_var($this->argument('amount'),FILTER_VALIDATE_INT);$r=$this->option('reason');if(!$c||$a===false||$a<=0||!in_array($r,GoldReasonCode::commandReasons(),true)){$this->error('Invalid character, amount or reason.');return 1;}try{$e=$s->credit($c,$a,$r,$this->option('description')?:null);$this->line("Type: credit\nAmount: {$e->amount()}\nBalance before: {$e->balanceBefore()}\nBalance after: {$e->balanceAfter()}\nReason: {$e->reasonCode()}");return 0;}catch(\Throwable $e){$this->error($e->getMessage());return 1;}}}
